1	# Dotfiles synchronization toolkit
2	#
3	# Manages syncing configuration files between this Git repository and the local machine.
4	# Uses two CSV files for configuration:
5	#   - paths-default.csv: Single column (full-path) with glob patterns. Repo paths are derived:
6	#     ~/.config/X/... → X/...  |  ~/.X/... → X/...
7	#   - paths-local.csv: Optional local overrides with status column (update, ignore)
8	#
9	# Commands:
10	#   pull-from-machine        - Copy configs from machine into repo
11	#   push-to-machine          - Copy configs from repo to machine (--dry-run for preview)
12	#   fill-candidates          - Find new config files to potentially track
13	#   cleanup-paths-not-in-csv - List repo files not tracked in CSV
14	#   install-skills           - Deploy Claude skills from sibling skill repos into ~/.claude/skills/
15	
16	const excluded_locals = [**/.git/** **/.jj/** toolkit.nu macos-fresh/* paths-default.csv paths-docker.csv README.md .gitignore CLAUDE.md .DS_Store .claude/settings.local.json paths-local.csv]
17	
18	const commit_target_dirs = [~/.config ~/.claude]
19	
20	export def main [] { }
21	
22	# Check if a file has uncommitted changes in its git repository
23	def has-uncommitted-changes [path: path] {
24	    if not ($path | path exists) { return false }
25	
26	    let dir = if ($path | path type) == 'dir' { $path } else { $path | path dirname }
27	
28	    # Check if inside a git repo
29	    let git_check = do { cd $dir; ^git rev-parse --git-dir } | complete
30	    if $git_check.exit_code != 0 { return false }
31	
32	    # Check for uncommitted changes (staged or unstaged)
33	    let status = do { cd $dir; ^git status --porcelain -- $path } | complete
34	    ($status.stdout | str trim | is-not-empty)
35	}
36	
37	# Check paths for uncommitted changes, print error if found. Returns true if dirty.
38	def check-dirty-files [paths: table field: string context: string] {
39	    let dirty = $paths | where { has-uncommitted-changes ($in | get $field) }
40	    if ($dirty | is-not-empty) {
41	        print $"(ansi red)Error: The following ($context) have uncommitted changes:(ansi reset)"
42	        $dirty | get $field | each { print $"  ($in)" }
43	        print $"\nCommit or stash changes first, or use --force to overwrite."
44	        true
45	    } else {
46	        false
47	    }
48	}
49	
50	# Derive repo path from full machine path using convention:
51	#   ~/.config/X/... → X/...
52	#   ~/.X/...        → X/...
53	def derive-repo-path [fullpath: string] {
54	    let expanded = $fullpath | path expand --no-symlink
55	    let home = $nu.home-dir
56	    let config_prefix = $home | path join '.config'
57	
58	    if ($expanded | str starts-with $config_prefix) {
59	        $expanded | str replace $"($config_prefix)/" ''
60	    } else if ($expanded | str starts-with $"($home)/.") {
61	        $expanded | str replace $"($home)/." ''
62	    } else {
63	        $expanded | str replace $"($home)/" ''
64	    }
65	}
66	
67	# Extract static prefix from glob pattern (everything before first glob char)
68	def glob-base [pattern: string] {
69	    $pattern | str replace -r '[\*\?\[\{].*$' ''
70	}
71	
72	# Read paths-default.csv, expand globs, and derive repo paths
73	def open-configs [paths_file: string = 'paths-default.csv'] {
74	    open $paths_file
75	    | get full-path
76	    | each {|pattern|
77	        let expanded = $pattern | path expand --no-symlink
78	        if ($pattern !~ '[\*\?\[\{]') {
79	            return [{full-path: $expanded path-in-repo: (derive-repo-path $expanded)}]
80	        }
81	
82	        let repo_pattern = derive-repo-path $expanded
83	        let machine_base = glob-base $expanded
84	        let repo_base = glob-base $repo_pattern
85	
86	        # Glob from machine (for pull) and repo (for push when machine dir missing)
87	        let from_machine = glob $expanded --no-dir
88	            | each {|f| {full-path: $f path-in-repo: (derive-repo-path $f)} }
89	
90	        let from_repo = glob $repo_pattern --no-dir
91	            | each {|f|
92	                let repo_path = $f | path relative-to (pwd)
93	                let rel = $repo_path | path relative-to $repo_base
94	                {path-in-repo: $repo_path full-path: ($machine_base | path join $rel)}
95	            }
96	
97	        $from_machine | append $from_repo | uniq-by path-in-repo
98	    }
99	    | flatten
100	}
101	
102	# Read paths-local.csv if it exists, otherwise return empty list
103	def open-local-configs [] {
104	    if ('paths-local.csv' | path exists) {
105	        open paths-local.csv | update full-path { path expand --no-symlink }
106	    } else { [] }
107	}
108	
109	# Merge local and default configs, applying ignore/update status and deduplication
110	def assemble-paths [paths_file: string = 'paths-default.csv'] {
111	    let local_statuses = open-local-configs
112	        | where status =~ '^update|ignore'
113	        | select full-path status
114	
115	    open-configs $paths_file
116	    | join --left $local_statuses full-path
117	    | where status? != ignore
118	}
119	
120	# Copy config files from the local machine into the repository
121	export def pull-from-machine [
122	    --force # overwrite files with uncommitted changes
123	] {
124	    let paths = assemble-paths
125	        | where {|i| $i.full-path | path exists }
126	
127	    if not $force and (check-dirty-files $paths path-in-repo "repo files") { return }
128	
129	    $paths
130	    | group-by { $in.path-in-repo | path dirname }
131	    | items {|dirname v|
132	        if ($dirname | path exists) { $v } else { mkdir $dirname; $v }
133	    }
134	    | flatten
135	    | each { cp $in.full-path $in.path-in-repo }
136	}
137	
138	# Show diff preview for a list of paths (repo → machine)
139	def show-push-diff [paths: table] {
140	    $paths | each {|row|
141	        if ($row.full-path | path exists) {
142	            let diff = ^git diff --no-index $row.full-path $row.path-in-repo | complete
143	            if ($diff.stdout | is-not-empty) {
144	                print $"\n=== ($row.full-path) ==="
145	                $diff.stdout | lines | skip 4 | str join (char newline) | print
146	            }
147	        } else {
148	            print $"\n=== ($row.full-path) ==="
149	            print $"(ansi yellow)→ NEW FILE will be created(ansi reset)"
150	            if not ($row.full-path | path dirname | path exists) {
151	                print $"(ansi red)  ⚠ Parent directory does not exist: ($row.full-path | path dirname)(ansi reset)"
152	            }
153	        }
154	    }
155	}
156	
157	# Copy config files from the repository to the local machine
158	export def push-to-machine [
159	    --create-dirs # in case of missing directories - create them in place
160	    --force # overwrite files with uncommitted changes
161	    --dry-run # show diff of what would change without copying
162	    --docker # use paths-docker.csv for Docker sandbox setup
163	    --commit-changes # git add + commit in target directories after push
164	] {
165	    let paths_file = if $docker { 'paths-docker.csv' } else { 'paths-default.csv' }
166	    let paths = assemble-paths $paths_file
167	        | where {|i| $i.path-in-repo | path exists }
168	
169	    if $dry_run {
170	        show-push-diff $paths
171	        return
172	    }
173	
174	    if not $force and (check-dirty-files $paths full-path "destination files") { return }
175	
176	    $paths
177	    | group-by { $in.full-path | path dirname }
178	    | items {|dirname v|
179	        if ($dirname | path exists) { $v } else {
180	            if $create_dirs { mkdir $dirname; $v }
181	        }
182	    }
183	    | compact
184	    | flatten
185	    | each { cp $in.path-in-repo $in.full-path }
186	
187	    # Create symlinks for PATH-accessible commands
188	    [
189	        [target link];
190	        ['~/.config/zellij/todo-nu/todo-hx.nu' '~/.local/bin/todo-hx']
191	        ['~/.config/zellij/hx-scrollback.nu' '~/.local/bin/hx-scrollback']
192	    ] | each {|s|
193	        let target = $s.target | path expand
194	        let link = $s.link | path expand --no-symlink
195	        if ($target | path exists) {
196	            mkdir ($link | path dirname)
197	            ^ln -sfn $target $link
198	        }
199	    }
200	
201	    # Initialize git repos for config directories
202	    $commit_target_dirs | each {|target_dir|
203	        let target_dir = $target_dir | path expand --no-symlink
204	        if not ($target_dir | path exists) {
205	            if $create_dirs { mkdir $target_dir } else { return }
206	        }
207	        if not ($target_dir | path join '.git' | path exists) { ^git init $target_dir }
208	    }
209	
210	    if $commit_changes {
211	        $commit_target_dirs | each {|target_dir|
212	            let target_dir = $target_dir | path expand --no-symlink
213	            if not ($target_dir | path join '.git' | path exists) { return }
214	
215	            let pushed_files = $paths
216	                | where { $in.full-path | str starts-with $"($target_dir)/" }
217	                | get full-path
218	
219	            if ($pushed_files | is-empty) { return }
220	
221	            $pushed_files | each { ^git -C $target_dir add $in }
222	            ^git -C $target_dir diff --cached --quiet ...$pushed_files
223	            | complete
224	            | if $in.exit_code != 0 {
225	                ^git -C $target_dir commit -m "push-to-machine" -- ...$pushed_files
226	            }
227	        }
228	    }
229	}
230	
231	# Scan tracked directories for new config files and update paths-local.csv
232	export def fill-candidates [] {
233	    let configs = open-configs
234	
235	    let local_configs = open-local-configs
236	
237	    let ignored_paths = $local_configs
