# Step 4 — deploy dotfiles. --docker selects paths-docker.csv inside the sandbox.
let dotfiles_dir = $nu.home-dir | path join 'repos' 'dotfiles'
let push_cmd = if $in_docker {
    'use toolkit.nu; toolkit push-to-machine --force --create-dirs --docker --commit-changes'
} else {
    'use toolkit.nu; toolkit push-to-machine --force --create-dirs --commit-changes'
}
^nu --no-config-file --commands $"cd ($dotfiles_dir); ($push_cmd)"

# Step 5 — deploy Claude skills from sibling skill repos under ~/repos/
^nu --no-config-file --commands $"cd ($dotfiles_dir); use toolkit.nu; toolkit install-skills --all"

