input.command:
cat <<'EOF'
print "=== 1. brew tools ==="
[nushell fzf lazygit helix zellij broot git-delta visidata bat topiary fd jj git-lfs]
| each { {tool: $in, installed: ((^brew list --formula $in | complete).exit_code == 0)} }
| print

print "=== 2. XDG git config ==="
try { open ~/.config/git/config | print } catch { print "MISSING ~/.config/git/config" }
try { open ~/.config/git/ignore | print } catch { print "MISSING ~/.config/git/ignore" }

print "=== 3. ~/repos fan-out ==="
ls ~/repos | select name type | print

print "=== 4a. nushell autoload ==="
try { ls ~/.config/nushell/autoload | get name | print } catch { print "MISSING autoload" }

print "=== 4b. .visidatarc ==="
try { ls ~/.visidatarc | select name size | print } catch { print "MISSING ~/.visidatarc" }

print "=== 5. dotfiles deployed ==="
[~/.config/helix ~/.config/zellij ~/.config/broot ~/.config/jj]
| each { {dir: $in, exists: ($in | path exists)} } | print

print "=== 6. claude skills ==="
try { ls ~/.claude/skills | get name | print } catch { print "MISSING ~/.claude/skills" }

print "=== 7. global CLAUDE.md append count (must be 1) ==="
try {
  open ~/.claude/CLAUDE.md
  | lines
  | where $it =~ '^# Sandbox Environment'
  | length
  | print
} catch { print "MISSING ~/.claude/CLAUDE.md" }

print "=== 8. broot init ==="
try { ls ~/.config/broot | get name | print } catch { print "MISSING ~/.config/broot" }

print "=== 9. topiary ==="
try { ls ~/.config/topiary/queries/nu.scm | select name size | print } catch { print "MISSING nu.scm" }
try { ls ~/.cache/topiary/nu | get name | print } catch { print "MISSING grammar cache" }

print "=== 10. claude + MCP ==="
^claude --version | print
^claude mcp list | print

print "=== 11. /etc/sandbox-persistent.sh ==="
try { open /etc/sandbox-persistent.sh | print } catch { print "MISSING" }

print "=== 12. cozy install bootstrap subcommand ==="
help cozy install bootstrap | print
EOF

